 384→interface ColorPickerViewProps {
 385→  colors: ColorItemData[];
 386→  onActiveIndexChange: (index: number) => void;
 387→  onAction: (index: number) => void;
 388→}
 389→
 390→function ColorPickerView({
 391→  colors,
 392→  onActiveIndexChange,
 393→  onAction,
 394→}: ColorPickerViewProps) {
 395→  if (colors.length === 0) {
 396→    return (
 397→      <EmptyState
 398→        icon={<SearchIcon />}
 399→        title="No Colors"
 400→        description="Try a different search term"
 401→      />
 402→    );
 403→  }
 404→
 405→  return (
 406→    <Grid
 407→      itemCount={colors.length}
 408→      columns={4}
 409→      onActiveIndexChange={onActiveIndexChange}
 410→      onAction={onAction}
 411→    >
 412→      {colors.map((color, index) => (
 413→        <GridItem
 414→          key={color.id}
 415→          index={index}
 416→          icon={<ColorSwatch color={color.color} />}
 417→          title={color.title}
 418→          subtitle={color.subtitle}
 419→        />
 420→      ))}
 421→    </Grid>
 422→  );
 423→}
