 425→function DetailView({ item }: { item: ListItemData }) {
 426→  const itemDetail = item.detail;
 427→  if (!itemDetail) return null;
 428→  return (
 429→    <Detail
 430→      markdown={itemDetail.markdown}
 431→      metadata={
 432→        itemDetail.metadata ? (
 433→          <DetailMetadata>
 434→            {itemDetail.metadata.map(renderMetadataEntry)}
 435→          </DetailMetadata>
 436→        ) : undefined
 437→      }
 438→    />
 439→  );
 440→}
