 442→export function App() {
 443→  const [query, setQuery] = useState('');
 444→  const [filterValue, setFilterValue] = useState('all');
 445→  const [selectedIndex, setSelectedIndex] = useState(0);
 446→  const [actionsOpen, setActionsOpen] = useState(false);
 447→  const { toasts, show: showToast, hide: hideToast } = useToast();
 448→  const { items: hudItems, show: showHUD } = useHUD();
 449→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 450→  const nav = useNavigationStack<NavViewData>('Raycast');
 451→  const { push, pop } = nav;
 452→
 453→  const viewType = nav.currentEntry?.data.type ?? 'root';
 454→
 455→  const searchFilterSections: SearchDropdownSection[] = useMemo(
 456→    () => [
 457→      {
 458→        options: [
 459→          {
