 462→          },
 463→        ],
 464→      },
 465→      {
 466→        title: 'Types',
 467→        options: [
 468→          {
 469→            label: 'Commands',
 470→            value: 'commands',
 471→          },
 472→          {
 473→            label: 'Applications',
 474→            value: 'applications',
 475→          },
 476→        ],
 477→      },
 478→    ],
 479→    [],
 480→  );
 481→
 482→  useEffect(() => {
