 556→        style: 'success',
 557→        title: 'Snippet Created',
 558→        message: form.name,
 559→      });
 560→      pop();
 561→    },
 562→    [
 563→      showToast,
 564→      pop,
 565→    ],
 566→  );
 567→
 568→  const handleDrillIn = useCallback(() => {
