 682→              />
 683→            ),
 684→            onClick: handleOpenCreateSnippet,
 685→          },
 686→        ],
 687→      },
 688→      {
 689→        title: 'Copy Actions',
 690→        actions: [
 691→          {
 692→            label: 'Copy Name',
 693→            shortcut: (
 694→              <Kbd
 695→                keys={[
 696→                  '⌘',
 697→                  'C',
 698→                ]}
 699→              />
