            <div className="command-palette__list-container">
              {allItems.length === 0 ? (
                <EmptyState
                  icon={<SearchIcon />}
                  title="No Results"
                  description="Try a different search term"
                />
              ) : (
                <List
                  itemCount={allItems.length}
                  onActiveIndexChange={handleActiveIndexChange}
                  onAction={handleDrillIn}
                >
                  {(() => {
                    let globalIndex = 0;
                    return filtered.map(section => (
                      <ListSection key={section.title} title={section.title}>
                        {section.items.map(item => {
                          const idx = globalIndex++;
                          return (
                            <ListItem
                              key={item.id}
                              index={idx}
                              title={item.title}
                              subtitle={item.subtitle}
                              icon={item.icon}
                              accessories={item.accessories}
                            />
                          );
                        })}
                      </ListSection>
                    ));
                  })()}
                </List>
              )}
            </div>
            {detail && (
              <Detail
                markdown={detail.markdown}
                metadata={
                  detail.metadata ? (
                    <DetailMetadata>
                      {detail.metadata.map(renderMetadataEntry)}
                    </DetailMetadata>
                  ) : undefined
                }
              />
            )}
          </div>
        )}
        <ActionPanel
          contextLabel={contextLabel}
          actions={
            viewType === 'form'
              ? [
                  {
                    label: 'Submit',
                    shortcut: (
                      <Kbd
                        keys={[
                          '⌘',
                          '↵',
                        ]}
                      />
                    ),
                  },
                ]
              : [
                  {
                    label: 'Open',
                    shortcut: <Kbd keys={['↵']} />,
                  },
                  {
                    label: 'Actions',
                    shortcut: (
                      <Kbd
                        keys={[
                          '⌘',
                          'K',
                        ]}
                      />
                    ),
                    onClick: toggleActions,
                  },
                ]
          }
          dropdownOpen={actionsOpen}
          dropdownSections={dropdownSections}
          onDropdownClose={closeActions}
        />
        {alertState && (
          <Alert
            title={alertState.title}
            message={alertState.message}
            icon={alertState.icon}
            primaryAction={alertState.primaryAction}
            dismissAction={alertState.dismissAction}
            onDismiss={dismissAlert}
          />
        )}
        <ToastContainer toasts={toasts} onDismiss={hideToast} />
        <HUDContainer items={hudItems} />
      </CommandPalette>
    </NavigationContextProvider>
  );
}

