            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      ),
      primaryAction: {
        label: 'Delete',
        style: 'destructive',
        onAction: () => {
          setEntries(prev => prev.filter(e => e.id !== entryId));
          showHUD({
            icon: <ClipboardHUDIcon />,
            title: 'Deleted',
          });
        },
      },
      dismissAction: {
        label: 'Cancel',
        style: 'cancel',
        onAction: () => {},
      },
    });
  }, [selectedEntry, confirmAlert, showHUD]);

  const handleAction = useCallback(() => {
    handlePaste();
  }, [handlePaste]);

  const toggleActions = useCallback(() => {
    setActionsOpen(prev => !prev);
  }, []);

  const closeActions = useCallback(() => {
    setActionsOpen(false);
  }, []);

  useKeyboardShortcut(
    { key: 'k', meta: true },
    toggleActions,
  );

  useKeyboardShortcut(
    { key: 'p', meta: true, shift: true },
    handleTogglePin,
  );

  useKeyboardShortcut(
    { key: 'Backspace', meta: true },
    handleDelete,
  );

  const dropdownSections: DropdownSection[] = useMemo(
    () => [
      {
        title: 'Actions',
        actions: [
          {
            label: 'Paste',
            shortcut: <Kbd keys={['↵']} />,
            onClick: handlePaste,
          },
          {
            label: 'Copy',
            shortcut: <Kbd keys={['⌘', 'C']} />,
            onClick: handleCopy,
          },
        ],
      },
      {
        title: 'Organize',
        actions: [
          {
            label: selectedEntry?.pinned ? 'Unpin' : 'Pin',
            shortcut: <Kbd keys={['⌘', '⇧', 'P']} />,
            onClick: handleTogglePin,
          },
        ],
